from collections import Counter

def generate_consciousness_report(subscriber_list, email_library):
    """
    Generates consciousness distribution + content gap analysis.

    Returns:
        dict: {
            'subscriber_distribution': dict,
            'email_coverage': dict,
            'gaps_identified': list,
            'recommendations': list
        }
    """
    # Subscriber distribution
    levels = [s.get('level_range', '1-3') for s in subscriber_list]
    level_counts = Counter(levels)
    total_subs = len(subscriber_list)

    subscriber_distribution = {
        '1-3': {
            'count': level_counts.get('1-3', 0),
            'percentage': round((level_counts.get('1-3', 0) / total_subs) * 100, 1) if total_subs > 0 else 0
        },
        '4-6': {
            'count': level_counts.get('4-6', 0),
            'percentage': round((level_counts.get('4-6', 0) / total_subs) * 100, 1) if total_subs > 0 else 0
        },
        '7-9': {
            'count': level_counts.get('7-9', 0),
            'percentage': round((level_counts.get('7-9', 0) / total_subs) * 100, 1) if total_subs > 0 else 0
        }
    }

    # Email coverage
    email_targets = [e.get('level_target', '1-3') for e in email_library]
    email_counts = Counter(email_targets)
    total_emails = len(email_library)

    email_coverage = {
        '1-3': {
            'count': email_counts.get('1-3', 0),
            'percentage': round((email_counts.get('1-3', 0) / total_emails) * 100, 1) if total_emails > 0 else 0
        },
        '4-6': {
            'count': email_counts.get('4-6', 0),
            'percentage': round((email_counts.get('4-6', 0) / total_emails) * 100, 1) if total_emails > 0 else 0
        },
        '7-9': {
            'count': email_counts.get('7-9', 0),
            'percentage': round((email_counts.get('7-9', 0) / total_emails) * 100, 1) if total_emails > 0 else 0
        }
    }

    # Gap analysis
    gaps_identified = []
    recommendations = []

    for level_range in ['1-3', '4-6', '7-9']:
        sub_pct = subscriber_distribution[level_range]['percentage']
        email_pct = email_coverage[level_range]['percentage']

        gap = sub_pct - email_pct

        if gap > 20:  # >20% more subscribers than emails at this level
            gaps_identified.append({
                'level_range': level_range,
                'type': 'undersupplied',
                'gap_percentage': round(gap, 1),
                'description': f'{sub_pct}% of subscribers are Level {level_range} but only {email_pct}% of emails target this range'
            })
            recommendations.append(f'Create more {level_range} content (current gap: {round(gap, 1)}%)')

        elif gap < -20:  # >20% more emails than subscribers at this level
            gaps_identified.append({
                'level_range': level_range,
                'type': 'oversupplied',
                'gap_percentage': round(abs(gap), 1),
                'description': f'{email_pct}% of emails target Level {level_range} but only {sub_pct}% of subscribers are at this range'
            })
            recommendations.append(f'Reduce {level_range} content OR focus on elevating subscribers to this range')

    # Overall health check
    if not gaps_identified:
        recommendations.append('Content mix well-balanced with subscriber distribution')

    return {
        'subscriber_distribution': subscriber_distribution,
        'email_coverage': email_coverage,
        'gaps_identified': gaps_identified,
        'recommendations': recommendations
    }
